import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"金蛇剑法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/金蛇剑法.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/金蛇剑法.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/白刃类/金蛇剑法.md"};function s(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"金蛇剑法",tabindex:"-1"},[b("金蛇剑法 "),r("a",{class:"header-anchor",href:"#金蛇剑法","aria-label":'Permalink to "金蛇剑法"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),n('<h1 id="金蛇剑法-1" tabindex="-1">金蛇剑法 <a class="header-anchor" href="#金蛇剑法-1" aria-label="Permalink to &quot;金蛇剑法&quot;">​</a></h1><p>金蛇剑法<br> 介绍：泛金庸武侠世界中&quot;金蛇郎君&quot;夏雪宜的成名武学。剑招阴狠毒辣，刁钻难测，然而许多招式却有着不和谐之处，导致威力平平，甚至毫无作用。必须结合五毒教三宝之一的金蛇剑，才能发挥这门剑法的真正威力。<br> 由于这些招式均为剑法，所以通常来说，需要使用分类为剑的冷兵器才能使用。</p><p>招式研发：你可以在持有金蛇剑或金蛇锥之后，消耗10XP，对于金蛇剑法的招式进行精研，发挥真正妙用。精研后的效果只有在持用金蛇剑和金蛇锥进行攻击时才能使用。每个研发效果都视为将原本的技艺提升至C级，并且如常因为提升至C级技艺而获得2点内在属性（因为D级已经提供过2点），也会因此享受评级上的减免。</p><p>金蛇吐信<br> 价格：D+500<br> 描述：金蛇剑法的第一式，犹如毒蛇狩猎前吐信试探，为而后的攻击找准时机。<br> 以一个标准动作，你消耗2点内力，进行一次攻击。这次攻击额外具有1点附加成功。在这次攻击造成伤害之后，由于你已经摸清了与对手的距离以及对手架势中的弱点，你下一次以金蛇剑法进行的攻击获得C级别的【措手不及】。<br> 如果你在已经施展过其他任意一式金蛇剑法的情况下施展这一招的话，那么你在下一次施展金蛇剑法时除了具有C级别的【措手不及】以外，还会额外具有B级别的【先制】。</p><p>研发效果：研发后，你以金蛇吐信进行攻击时，消耗的内力翻倍，并且改为额外具有2点附加成功，获得的【措手不及】升级到B，同时【先制】升级到A级。</p><p>杯弓蛇影<br> 价格：D+500<br> 描述：金蛇剑法的第二式，剑势犹如杯中突然显出的蛇影一般飘忽不定，令敌人琢磨不透，自生疑虑。<br> 以一个标准动作，你消耗2点内力，进行一次攻击。这次攻击额外附带你的传奇敏捷*3点的技艺加值。<br> 如果你在已经施展过其他任意一式金蛇剑法的情况下施展这一招的话，对手会因为你先前的攻击与这次攻击之间的剑招变化而疑惑，从而被你快速的剑舞迷惑视线，使你获得等同于传奇敏捷*2点的【蛇影】，【蛇影】在计算时视为高速，但最多可以将你传奇敏捷*1+1点【蛇影】带来的高速转为威猛。<br> 研发效果：研发后，你以杯弓蛇影进行攻击时，消耗的内力翻倍，在保留原有效果的基础上，每轮一次，你可以在攻击的判定得出出目后，可以选择重新投掷一次，无论好坏，你都必须接受第二次结果。<br> 并且此时你如果已经施展过其他一式金蛇剑法施展这一招的话，这次招式除了具有原本的追加效果外，还会使得敌人在下一次应对金蛇狂舞的反射检定上受到7点的技艺减值和失去1点附加成功。</p><p>金蛇狂舞<br> 价格：D+500<br> 描述：金蛇剑法的第三式，剑势肆意泼洒而出，宛如蛇蟒倾巢而出，杀机连绵不绝。<br> 以一个标准动作，你消耗2点内力，进行一次攻击。这次攻击不经过防御，而是需要以反射检定进行豁免，并且由于你的出招接连不断，这次攻击具有【连射】的速射等级，但如果是白刃攻击，则无需实际消费弹药。<br> 如果你在已经施展过其他两招金蛇剑法的情况下施展这一招的话，由于你已经在剑刃之中积累了足够的内力，当这一招泼洒而出之际，你的剑招的攻势杀向对手周身穴道，并且内劲贯入体内，宛如蛇毒一样乱人体内经脉。这会使得你这次攻击额外附带等同伤害出目的恶心，目眩和疲乏点数，正常豁免，可叠加。<br> 研发效果：研发后，你以金蛇狂舞进行攻击时，消耗的内力翻倍，在保留原有效果的基础上，你通过连射获得的DP加值提升4点。<br> 并且此时如果你在已经施展过其他两招金蛇剑法的情况下施展这一招的话，这次招式除了具有原本的效果外，还会再提升4点连射上的dp加值，并且附带等同伤害出目二分之一的耐力的属性伤害，以强韧检定豁免。</p><p>专属物品：</p><p>金蛇剑<br> 价格：C+1000<br> 描述：五毒教三宝之一，形制独特，据说只有这柄剑才能发挥出来金蛇剑法的真正威力。<br> 这是一柄具有11L武器伤害和6点破甲的轻剑。由于这柄剑形制特殊，剑身弯曲，好似蛇行曲折，又有叉开的剑尖，宛如蛇信之形，所以金蛇剑法在以此剑施展时会发挥完全的威力。你在持用此剑使用金蛇剑法时，额外获得4点器械加值和1点附加成功。</p><p>金蛇锥<br> 价格：C+1000<br> 描述：五毒教三宝之一，形制独特，金蛇郎君夏雪宜凭此修得独特的暗器手法。<br> 这是一柄具有11L武器伤害和6点破甲的投掷武器。一次兑换可以获得24个，视为具有【无限子弹】特性。由于这些金锥形制特殊，宛如蛇形，与金蛇剑的形制有诸多异曲同工之处，所以你在持用这些金蛇锥时，也可以如常以投掷施展金蛇剑法的技艺进行攻击，并且在使用金蛇剑法的招式进行攻击时，额外具有3点器械加值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(o,[["render",s]]);export{f as __pageData,m as default};
